+/*
+ * E2M1 to float
+ * 0111 -> 6
+ * 0110 -> 4
+ * 0101 -> 3
+ * 0100 -> 2
+ * 0011 -> 1.5
+ * 0010 -> 1
+ * 0001 -> 0.5
+ * 0000 -> 0
+ */
+static float const kE2M1ToFloatArray[] = {0, 0.5, 1, 1.5, 2, 3, 4, 6};
+static float const kE2M1Array[] = {0, 0.25, 0.75, 1.25, 1.75, 2.5, 3.5, 5};
+static int const kE2M1Count = 8;
